"use client";

import type { FC } from "react";

/* ─────────────────────────────────────────────────────────────────
   Flagship family tile art — filled brand silhouettes (Core, Managed,
   Specialized) plus a stroked NA map for Cross-Border.

   • Family accent drives fills via `currentColor` on the main paths.
   • Cross-Border adds `--scene-ink` corridor strokes and waypoints.
   • viewBoxes are content-cropped (not the raw exporter boxes) so the
     four illustrations render at consistent visual density inside
     their tiles — no illustration floats in a box of whitespace.
   ───────────────────────────────────────────────────────────────── */

